// admin-login.jsx
import axiosInstance from "../axiosConfig";
import { useFormik } from "formik";
import { useCookies } from "react-cookie";
import { useNavigate } from "react-router-dom";

export function AdminLogin() {
    const navigate = useNavigate();
    const [cookies, setCookie] = useCookies(['admin-id']);

    const formik = useFormik({
        initialValues: {
            UserId: '',
            Password: ''
        },
        onSubmit: (admin) => {
            const inputId = admin.UserId.toLowerCase().trim();
            const inputPass = admin.Password;

            axiosInstance.get('/get-admin')
                .then(response => {
                    const admins = response.data;

                    if (Array.isArray(admins) && admins.length > 0) {
                        const match = admins.find(a =>
                            a &&
                            typeof a.UserId === 'string' &&
                            typeof a.Password === 'string' &&
                            a.UserId.toLowerCase().trim() === inputId &&
                            a.Password === inputPass
                        );

                        if (match) {
                            setCookie('admin-id', match.UserId, { path: '/' });
                            navigate('/admin-dashboard');
                            window.location.reload();
                        } else {
                            alert("Invalid Admin ID or Password");
                            navigate('/admin-error');
                        }
                    } else {
                        alert("No admin found");
                    }
                })
                .catch(err => {
                    console.error("Error fetching admin data:", err);
                    alert("Server error, try again later");
                });
        }
    });

    return (
        <div className="d-flex justify-content-center align-items-center" style={{ height: '60vh' }}>
            <form className="w-25" onSubmit={formik.handleSubmit} autoComplete="on">
                <div className="text-center bi bi-person-circle fs-3 mb-3">Admin Login</div>
                <dl>
                    <dt>Admin Id</dt>
                    <dd>
                        <input
                            type="text"
                            name="UserId"
                            onChange={formik.handleChange}
                            className="form-control"
                            autoComplete="username"
                        />
                    </dd>
                    <dt>Password</dt>
                    <dd>
                        <input
                            type="password"
                            name="Password"
                            onChange={formik.handleChange}
                            className="form-control"
                            autoComplete="current-password"
                        />
                    </dd>
                </dl>
                <button type="submit" className="btn btn-danger w-100">Login</button>
            </form>
        </div>
    );
}
